const input = $input.first().json;
const data = input.body || input;
const { nombre, tipo, nivel, categoria, dia_1, dia_2, hora_inicio, hora_fin, cupo_max, precio_mensual, descripcion } = data;

if (!nombre || !tipo || !nivel || !categoria || !dia_1 || !dia_2 || !hora_inicio || !hora_fin || !cupo_max) {
  throw new Error(`Faltan campos requeridos`);
}

const nom = String(nombre).replace(/'/g, "''");
const des = descripcion ? String(descripcion).replace(/'/g, "''") : null;

const query = `INSERT INTO horarios (nombre, tipo, nivel, categoria, dia_1, dia_2, hora_inicio, hora_fin, cupo_max, cupo_actual, precio_mensual, descripcion, activo) VALUES ('${nom}', '${tipo}', '${nivel}', '${categoria}', '${dia_1}', '${dia_2}', '${hora_inicio}'::time, '${hora_fin}'::time, ${parseInt(cupo_max)}, 0, ${precio_mensual ? parseFloat(precio_mensual) : 'null'}, ${des ? `'${des}'` : 'null'}, true) RETURNING id, nombre, tipo, nivel, categoria, dia_1, dia_2, hora_inicio, hora_fin, cupo_max, activo;`;

return [{
  json: {
    query
  }
}];

const resultado = $('query_db').all();

if (resultado.length === 0) {
  throw new Error('Error al crear horario');
}

const horario = resultado[0].json;

return [{
  json: {
    success: true,
    message: 'Horario creado correctamente',
    horario: horario
  }
}];
